const raw = $input.first().json;
const input = raw.body || raw;

const name = (input.name || input.Name || input.full_name || '').toString().trim();
const phone = (input.phone || input.Phone || '').toString().replace(/[^\d+]/g, '');
const email = (input.email || input.Email || '').toString().toLowerCase().trim();
const message = (input.message || input.Message || '').toString().trim();
const source = (input.source || input.Source || 'Website Form').toString().trim();

if (!name || name.length < 2) throw new Error('Name is required');
if (!phone && !email) throw new Error('Phone or email is required');
if (phone && phone.length < 10) throw new Error('Invalid phone number');
if (email && !email.includes('@')) throw new Error('Invalid email address');

return { json: { name, phone, email, source, message, timestamp: new Date().toISOString() } };

const record = $('Check Duplicate').item.json.records[0];
const lead = $('Normalize Data').item.json;
const note = '[' + lead.timestamp + '] Returned via ' + lead.source + ': ' + lead.message;

const fields = {
  InteractionCount: (record.fields.InteractionCount || 0) + 1,
  LastSeen: lead.timestamp,
  Notes: (record.fields.Notes || '') + (record.fields.Notes ? ' | ' : '') + note
};

if (!record.fields.Name && lead.name) fields.Name = lead.name;
if (!record.fields.Phone && lead.phone) fields.Phone = lead.phone;
if (!record.fields.Email && lead.email) fields.Email = lead.email;
if (!record.fields.Source && lead.source) fields.Source = lead.source;

return { json: { recordId: record.id, body: { fields }, isReturning: true } };

const lead = $('Normalize Data').item.json;

return {
  json: {
    body: {
      fields: {
        Name: lead.name,
        Phone: lead.phone,
        Email: lead.email,
        Source: lead.source,
        Status: 'New',
        LeadScore: 0,
        InteractionCount: 1,
        LastSeen: lead.timestamp,
        Notes: '[' + lead.timestamp + '] Initial inquiry: ' + lead.message
      }
    },
    isReturning: false
  }
};

const item = $input.first().json;
const lead = $('Normalize Data').item.json;

// Build scoring data with all required fields
const scoringData = {
  contact_id: item.id,
  contact_name: item.fields.Name || lead.name,
  lead_data: {
    name: item.fields.Name || lead.name,
    phone: item.fields.Phone || lead.phone,
    email: item.fields.Email || lead.email,
    source: item.fields.Source || lead.source,
    message: lead.message,
    interaction_count: item.fields.InteractionCount || 1
  }
};

return { json: scoringData };
